SELECT ?question ?result WHERE {
  VALUES (?question) {
    ("How many emperors did China have?" )
    ("Give me all female German chancellors." )
    ("How many movies did Park Chan-wook direct?" )
  }

  BIND(
    IF(?question = "How many emperors did China have?",
      (SELECT (COUNT(DISTINCT ?emperor) AS ?count) WHERE {
        ?emperor wdt:P39 wd:Q268218 .
      }),
    IF(?question = "Give me all female German chancellors.",
      (SELECT (GROUP_CONCAT(DISTINCT STR(?chancellor); separator=", ") AS ?count) WHERE {
        ?chancellor wdt:P21 wd:Q6581072 .
        ?chancellor wdt:P39 wd:Q4970706 .
      }),
    IF(?question = "How many movies did Park Chan-wook direct?",
      (SELECT (COUNT(DISTINCT ?movie) AS ?count) WHERE {
        ?movie wdt:P57 wd:Q315484 .
      }),
      ""    
    ))) AS ?result)
}

