PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?highestVolcano ?capitalCameroon ?largestCountry WHERE {
  # Highest volcano in Africa
  ?highestVolcano wdt:P31/wdt:P279* wd:Q8072 ;          # instance of volcano
                   wdt:P30 wd:Q15 ;                   # continent Africa
                   wdt:P2044 ?elevation .             # elevation in meters
  FILTER NOT EXISTS {
    ?otherVolcano wdt:P31/wdt:P279* wd:Q8072 ;
                  wdt:P30 wd:Q15 ;
                  wdt:P2044 ?otherElevation .
    FILTER(?otherElevation > ?elevation)
  }

  # Capital of Cameroon
  wd:Q1009 wdt:P36 ?capitalCameroon .

  # Largest country in the world
  ?largestCountry wdt:P31 wd:Q6256 ;                    # instance of country
                  wdt:P2046 ?area .
  FILTER NOT EXISTS {
    ?otherCountry wdt:P31 wd:Q6256 ;
                  wdt:P2046 ?otherArea .
    FILTER(?otherArea > ?area)
  }

  # Labels (optional, for better readability)
  OPTIONAL { ?highestVolcano rdfs:label ?highestVolcanoLabel FILTER(LANG(?highestVolcanoLabel) = "en") }
  OPTIONAL { ?capitalCameroon rdfs:label ?capitalLabel FILTER(LANG(?capitalLabel) = "en") }
  OPTIONAL { ?largestCountry rdfs:label ?largestCountryLabel FILTER(LANG(?largestCountryLabel) = "en") }
}
LIMIT 1

